import { Component, OnInit } from '@angular/core';
import { BookService } from '../../services/book.service';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-issue-book',
  templateUrl: './issue-book.component.html',
  styleUrls: ['./issue-book.component.css']
})
export class IssueBookComponent implements OnInit {
  books: any[] = [];
  availableBooks: any[] = [];
  selectedBookId: string = '';
  isLoading: boolean = false;
  successMessage: string = '';
  errorMessage: string = '';

  currentUser: any = null;
  userIssuedBooks: any[] = [];

  constructor(private bookService: BookService, private authService: AuthService) {}

  ngOnInit(): void {
    this.currentUser = this.authService.getCurrentUser();
    this.loadBooks();
    this.loadUserIssuedBooks();
  }

  loadBooks(): void {
    this.books = this.bookService.getBooks();
    this.availableBooks = this.books.filter((book: any) => book.availableQuantity > 0);
  }

  loadUserIssuedBooks(): void {
    if (this.currentUser) {
      this.userIssuedBooks = this.bookService.getIssuedBooksByUser(this.currentUser.id)
        .filter((book: any) => book.status === 'issued');
    }
  }

  issueBook(): void {
    if (!this.selectedBookId) {
      this.errorMessage = 'Please select a book to issue';
      return;
    }

    if (!this.currentUser) {
      this.errorMessage = 'Please login to issue books';
      return;
    }

    this.isLoading = true;
    this.errorMessage = '';
    this.successMessage = '';

    const result = this.bookService.issueBook(this.selectedBookId, this.currentUser.id);

    if (result.success) {
      this.successMessage = result.message;
      this.selectedBookId = '';
      this.loadBooks();
      this.loadUserIssuedBooks();
    } else {
      this.errorMessage = result.message;
    }

    this.isLoading = false;

    setTimeout(() => {
      this.clearMessages();
    }, 3000);
  }

  clearMessages(): void {
    this.successMessage = '';
    this.errorMessage = '';
  }

  getBookTitle(bookId: string): string {
    const book = this.books.find(b => b.id === bookId);
    return book ? book.title : 'Unknown Book';
  }

  getDueStatus(dueDate: Date | string): string {
    const due = new Date(dueDate);
    const today = new Date();
    const daysLeft = Math.ceil((due.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

    if (daysLeft < 0) {
      return `Overdue by ${Math.abs(daysLeft)} days`;
    } else if (daysLeft === 0) {
      return 'Due today';
    } else if (daysLeft === 1) {
      return 'Due tomorrow';
    } else {
      return `${daysLeft} days left`;
    }
  }

  isOverdue(dueDate: Date | string): boolean {
    return new Date(dueDate) < new Date();
  }

  formatDate(date: Date | string): string {
    const d = new Date(date);
    return d.toLocaleDateString('en-US', { 
      year: 'numeric', 
      month: 'short', 
      day: 'numeric' 
    });
  }

  returnBook(issuedBookId: string): void {
    if (confirm('Are you sure you want to return this book?')) {
      const result = this.bookService.returnBook(issuedBookId);

      if (result.success) {
        this.successMessage = result.message;
        this.loadBooks();
        this.loadUserIssuedBooks();
      } else {
        this.errorMessage = result.message;
      }

      setTimeout(() => {
        this.clearMessages();
      }, 3000);
    }
  }
}
<div class="issue-book-container">
  <div class="page-header">
    <h1>📖 Issue Book</h1>
    <p>Borrow books from the library</p>
  </div>

  <!-- Messages -->
  <div class="message-container">
    <div class="error-message" *ngIf="errorMessage">
      {{ errorMessage }}
      <button class="close-btn" (click)="clearMessages()">×</button>
    </div>

    <div class="success-message" *ngIf="successMessage">
      {{ successMessage }}
      <button class="close-btn" (click)="clearMessages()">×</button>
    </div>
  </div>

  <div class="content-grid">
    <!-- Issue New Book Section -->
    <div class="issue-section">
      <div class="section-card">
        <h2>Issue New Book</h2>

        <div class="form-group">
          <label for="bookSelect">Select Book</label>
          <select 
            id="bookSelect" 
            name="bookSelect" 
            [(ngModel)]="selectedBookId"
            class="book-select"
          >
            <option value="">-- Choose a book --</option>
            <option 
              *ngFor="let book of availableBooks" 
              [value]="book.id"
            >
              {{ book.title }} - {{ book.author }} ({{ book.availableQuantity }} available)
            </option>
          </select>
        </div>

        <button 
          class="issue-btn" 
          (click)="issueBook()" 
          [disabled]="!selectedBookId || isLoading"
        >
          <span *ngIf="!isLoading">📚 Issue Book</span>
          <span *ngIf="isLoading">Processing...</span>
        </button>

        <div *ngIf="availableBooks.length === 0" class="no-books">
          <p>📚 No books are currently available for issuing.</p>
        </div>
      </div>
    </div>

    <!-- Current Issued Books Section -->
    <div class="current-issues-section">
      <div class="section-card">
        <h2>My Current Books ({{ userIssuedBooks.length }})</h2>

        <div *ngIf="userIssuedBooks.length === 0" class="empty-state">
          <p>📖 You haven't issued any books yet.</p>
        </div>

        <div class="issued-books-list" *ngIf="userIssuedBooks.length > 0">
          <div 
            *ngFor="let issuedBook of userIssuedBooks" 
            class="issued-book-item"
          >
            <div class="book-info">
              <h4>{{ getBookTitle(issuedBook.bookId) }}</h4>
              <p class="issue-date">Issued: {{ formatDate(issuedBook.issueDate) }}</p>
              <p class="due-date">Due: {{ formatDate(issuedBook.dueDate) }}</p>
              <span 
                class="due-status" 
                [class.overdue]="isOverdue(issuedBook.dueDate)"
              >
                {{ getDueStatus(issuedBook.dueDate) }}
              </span>
            </div>

            <div class="book-actions">
              <button 
                class="return-btn" 
                (click)="returnBook(issuedBook.id)"
                title="Return this book"
              >
                📤 Return
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>

  <!-- Instructions -->
  <div class="instructions-card">
    <h3>📋 Instructions</h3>
    <ul>
      <li>Select a book from the dropdown to issue a new book</li>
      <li>Books are issued for 14 days</li>
      <li>A fine of ₹5 per day will be charged for late returns</li>
      <li>You can return books from this page or the Return Book page</li>
      <li>Make sure to return books on time to avoid fines</li>
    </ul>
  </div>
</div>
